import java.text.SimpleDateFormat;
              import java.util.Date;
              import java.text.ParseException;
              import sailpoint.object.Custom;
              import sailpoint.tools.Util;
              import org.apache.commons.logging.Log;
              import org.apache.commons.logging.LogFactory;
              Log logger = LogFactory.getLog("script.Ascension.AD.Field.Description");

              Date date = new Date();
              String dateString = null;
              String format = "";

              Custom custom = context.getObjectByName(Custom.class, "Ascension-Custom-ContractorConfiguration");
              try{
              if(custom!=null && Util.isNotNullOrEmpty(custom.get("DateFormat"))){
              format = custom.get("DateFormat");
              }

              SimpleDateFormat dateFormatIIQ = new SimpleDateFormat(format);
              if(null != date){
              dateString = dateFormatIIQ.format(date);
              }  
              }catch(Exception ex){
              logger.error("Exception in Converting Date to String"+ex);
              }

              if(null != custom){
              //comment decache //context.decache(custom);
              }

              String description = "Automatically Provisioned By IdentityIQ - ["+dateString+"]";
              return description;
